  background: var(--mf-surface, var(--mf-preset-surface, #fffaf0));
}

/* ---------- Hidden ---------- */
.mfp.mfp-classic-americana-registration .mfp-hidden {
  display: none;
}

/* ============================================================
   RESPONSIVE
   ============================================================ */
